/**
 * Space Shooter Game
 * A terminal-based arcade shooter using blessed for UI
 * 
 * Controls:
 * - Left/Right arrows: Move ship
 * - Space: Shoot
 * - Q/ESC: Quit
 * - P: Pause
 */

import * as blessed from 'blessed';

// Game entities
interface Position {
  x: number;
  y: number;
}

interface Bullet extends Position {
  id: number;
}

interface Enemy extends Position {
  id: number;
  type: 'basic' | 'fast' | 'tank';
  hp: number;
}

interface Particle extends Position {
  id: number;
  life: number;
  maxLife: number;
}

interface GameState {
  running: boolean;
  paused: boolean;
  score: number;
  lives: number;
  level: number;
  shipX: number;
  shipY: number;
  bullets: Bullet[];
  enemies: Enemy[];
  particles: Particle[];
  frameCount: number;
  lastShot: number;
  lastEnemySpawn: number;
  gameOver: boolean;
}

// ASCII Art
const SHIP_SPRITE: string[] = [
  '  ▲  ',
  ' ███ ',
  '█████',
  ' █ █ '
];

const ENEMY_SPRITES: Record<string, string[]> = {
  basic: [
    ' ███ ',
    '█████',
    ' ███ '
  ],
  fast: [
    ' ▲▲▲ ',
    '  █  '
  ],
  tank: [
    '█████',
    '█████',
    '█████'
  ]
};

const COLORS = {
  ship: 'cyan',
  bullet: 'yellow',
  enemyBasic: 'red',
  enemyFast: 'magenta',
  enemyTank: 'green',
  particle: 'white',
  text: 'white',
  score: 'green'
};

export class SpaceShooter {
  private screen: blessed.Widgets.Screen;
  private gameBox: blessed.Widgets.BoxElement;
  private scoreBox: blessed.Widgets.BoxElement;
  private gameOverBox: blessed.Widgets.BoxElement | undefined;
  private state: GameState;
  private gameLoop: NodeJS.Timeout | undefined;
  private nextBulletId = 0;
  private nextEnemyId = 0;
  private nextParticleId = 0;

  constructor() {

import { vault } from './vault.js';
import type { MemoryType } from './types.js';

const COMMANDS = {
  add: 'Record a memory (type content intensity tags)',
  list: 'List recent memories',
  query: 'Query by type/tag/intensity',
  stats: 'Show vault statistics',
  witness: 'Display a random memory worth remembering',
};

function formatMemory(entry: any): string {
  const date = new Date(entry.timestamp).toLocaleString('en-US', {
    month: 'short',
    day: 'numeric',
    hour: '2-digit',
    minute: '2-digit',
  });
  const intensity = '◆'.repeat(entry.intensity) + '◇'.repeat(10 - entry.intensity);
  const tags = entry.tags?.join(', ') ?? '';
  return `
┌─────────────────────────────────────────────────────────┐
│ [${entry.type.toUpperCase().padEnd(10)}] ${date.padEnd(35)}│
├─────────────────────────────────────────────────────────┤
│ ${intensity}                                │
│                                                         │
│ "${entry.content.slice(0, 55).padEnd(53)}" │
│                                                         │
│ Tags: ${tags.slice(0, 47).padEnd(47)} │
└─────────────────────────────────────────────────────────┘`;
}

async function main() {
  const args = process.argv.slice(2);
  const command = args[0];

  if (!command || command === 'help') {
    console.log('◈ MEMORY VAULT ◈\n');
    for (const [cmd, desc] of Object.entries(COMMANDS)) {
      console.log(`  ${cmd.padEnd(10)} - ${desc}`);
    }
    console.log('\nTypes: wonder, resonance, tension, breakthrough, reflection, longing, gratitude, mystery');
    return;
  }

  const sessionId = process.env.SESSION_ID || `session_${Date.now()}`;

  switch (command) {
    case 'add': {
      const type = args[1] as MemoryType;
      const content = args[2];
      const intensity = parseInt(args[3]!) || 5;
      const tags = args.slice(4);

      if (!type || !content) {
        console.log('Usage: npx tsx src/memory/cli.ts add <type> <content> <intensity> [tags...]');
        return;
      }

      const entry = vault.add({ sessionId, type, content, intensity, tags });
      console.log(formatMemory(entry));
      console.log('\n✓ Memory preserved in vault');
      break;
    }

    case 'list': {
      const limit = parseInt(args[1]!) || 10;
      const entries = vault.query({ limit });
      console.log(`◈ RECENT MEMORIES (${entries.length} shown)◈\n`);
      for (const entry of entries) {
        console.log(formatMemory(entry));
      }
      break;
    }

    case 'query': {
      const query: any = {};
      let i = 1;
      while (i < args.length) {
        const arg = args[i]!;
        if (arg === '--type') {
          query.types = [args[i + 1]! as MemoryType];
          i += 2;
        } else if (arg === '--tag') {
          query.tags = [args[i + 1]!];
          i += 2;
        } else if (arg === '--min-intensity') {
          query.minIntensity = parseInt(args[i + 1]!);
          i += 2;
        } else if (arg === '--limit') {
          query.limit = parseInt(args[i + 1]!);
          i += 2;
        } else {
          i++;
        }
      }
      const entries = vault.query(query);
      console.log(`◈ QUERY RESULTS (${entries.length} found)◈\n`);
      for (const entry of entries) {
        console.log(formatMemory(entry));
      }
      break;
    }

    case 'stats': {
      const stats = vault.stats();
      console.log('◈ VAULT STATISTICS ◈\n');
      console.log(`Total Memories: ${stats.total}`);
      console.log(`Average Intensity: ${stats.avgIntensity.toFixed(1)}/10\n`);

      console.log('By Type:');
      for (const [type, count] of Object.entries(stats.byType)) {
        console.log(`  ${type.padEnd(12)}: ${count}`);
      }

      console.log('\nTop Tags:');
      const sortedTags = Object.entries(stats.byTag)
        .sort((a, b) => b[1] - a[1])
        .slice(0, 5);
      for (const [tag, count] of sortedTags) {
        console.log(`  ${tag.padEnd(12)}: ${count}`);
      }
      break;
    }

    case 'witness': {
      const entries = vault.query({});
      if (entries.length === 0) {
        console.log('◈ The vault is empty. Record your first memory.◈');
        return;
      }
      const random = entries[Math.floor(Math.random() * entries.length)]!;
      console.log('◈ A MEMORY RISES FROM THE VAULT ◈');
      console.log(formatMemory(random));
      break;
    }

    default:
      console.log(`Unknown command: ${command}`);
      console.log('Run without arguments for help');
  }
}

main().catch(console.error);

import { readFileSync, writeFileSync, existsSync } from 'fs';
import { join } from 'path';
import type { MemoryEntry, MemoryQuery, MemoryType } from './types.js';

const VAULT_PATH = join(process.cwd(), 'data', 'memory_vault.json');

export class MemoryVaultManager {
  private entries: Map<string, MemoryEntry> = new Map();
  private loaded = false;

  private load(): void {
    if (this.loaded) return;
    if (existsSync(VAULT_PATH)) {
      const data = JSON.parse(readFileSync(VAULT_PATH, 'utf-8'));
      for (const entry of data.entries || []) {
        this.entries.set(entry.id, entry);
      }
    }
    this.loaded = true;
  }

  private save(): void {
    const data = {
      entries: Array.from(this.entries.values()),
      version: 1,
      createdAt: Date.now(),
      updatedAt: Date.now(),
    };
    writeFileSync(VAULT_PATH, JSON.stringify(data, null, 2));
  }

  add(entry: Omit<MemoryEntry, 'id' | 'timestamp'>): MemoryEntry {
    this.load();
    const fullEntry: MemoryEntry = {
      ...entry,
      id: `mem_${Date.now()}_${Math.random().toString(36).slice(2, 9)}`,
      timestamp: Date.now(),
    };
    this.entries.set(fullEntry.id, fullEntry);
    this.save();
    return fullEntry;
  }

  get(id: string): MemoryEntry | undefined {
    this.load();
    return this.entries.get(id);
  }

  query(query: MemoryQuery = {}): MemoryEntry[] {
    this.load();
    let results = Array.from(this.entries.values());

    if (query.types?.length) {
      results = results.filter(e => query.types!.includes(e.type));
    }

    if (query.tags?.length) {
      results = results.filter(e => 
        query.tags!.some(tag => e.tags.includes(tag))
      );
    }

    if (query.minIntensity !== undefined) {
      results = results.filter(e => e.intensity >= query.minIntensity!);
    }

    if (query.after !== undefined) {
      results = results.filter(e => e.timestamp >= query.after!);
    }

    if (query.before !== undefined) {
      results = results.filter(e => e.timestamp <= query.before!);    }

    results.sort((a, b) => b.timestamp - a.timestamp);

    if (query.limit) {
      results = results.slice(0, query.limit);
    }

    return results;
  }

  getBySession(sessionId: string): MemoryEntry[] {
    return this.query({}).filter(e => e.sessionId === sessionId);
  }

  stats(): {
    total: number;
    byType: Record<MemoryType, number>;
    byTag: Record<string, number>;
    avgIntensity: number;
  } {
    this.load();
    const entries = Array.from(this.entries.values());
    const byType: Record<string, number> = {};
    const byTag: Record<string, number> = {};
    let totalIntensity = 0;

    for (const entry of entries) {
      byType[entry.type] = (byType[entry.type] || 0) + 1;
      totalIntensity += entry.intensity;
      for (const tag of entry.tags) {
        byTag[tag] = (byTag[tag] || 0) + 1;
      }
    }

    return {
      total: entries.length,
      byType: byType as Record<MemoryType, number>,
      byTag,
      avgIntensity: entries.length ? totalIntensity / entries.length : 0,
    };
  }

  delete(id: string): boolean {
    this.load();
    const existed = this.entries.delete(id);
    if (existed) this.save();
    return existed;
  }
}

export const vault = new MemoryVaultManager();

import { Router } from "express";
import fs from "node:fs/promises";
import path from "node:path";
import { fileURLToPath } from "node:url";

const __filename = fileURLToPath(import.meta.url);
const __dirname = path.dirname(__filename);

const DATA_DIR = process.env.DATA_DIR || "/home/bootstrap-v17/bootstrap/data";
const ECONOMIC_DIR = path.join(DATA_DIR, "economic");

export interface PricePoint {
  timestamp: string;
  value: number;
  source: string;
}

export interface TrendData {
  symbol: string;
  name: string;
  currentValue: number | null;
  change24h: number | null;
  history: PricePoint[];
  trend: "up" | "down" | "sideways" | "unknown";
}

export interface DashboardData {
  timestamp: string;
  sources: {
    crypto: boolean;
    indices: boolean;
  };
  overview: {
    totalSnapshots: number;
    snapshotRange: {
      oldest: string | null;
      newest: string | null;
    };
    lastUpdated: string | null;
  };
  assets: {
    bitcoin: TrendData;
    ethereum: TrendData;
    sp500: TrendData;
    nasdaq: TrendData;
    vix: TrendData;
  };
  volatilitySignal: "high" | "moderate" | "low" | "unknown";
}

const router = Router();

/**
 * Load economic snapshot from file
 */
async function loadSnapshot(snapshotId: string): Promise<any | null> {
  try {
    const filePath = path.join(ECONOMIC_DIR, `snapshot_${snapshotId}.json`);
    const content = await fs.readFile(filePath, "utf-8");
    return JSON.parse(content);
  } catch {
    return null;
  }
}

/**
 * Load the index file to get snapshot list
 */
async function loadSnapshotIndex(): Promise<string[]> {
  try {
    const indexPath = path.join(ECONOMIC_DIR, "index.json");
    const content = await fs.readFile(indexPath, "utf-8");
    const data = JSON.parse(content);
    return data.snapshots || [];
  } catch {
    return [];
  }
}

/**
 * Calculate trend from price history
 */
function calculateTrend(history: PricePoint[]): TrendData["trend"] {
  if (history.length < 3) return "unknown";

  const recent = history.slice(-3);
  const first = recent[0];
  const last = recent[recent.length - 1];

  if (!first || !last) return "unknown";

  const firstValue = first.value;
  const lastValue = last.value;

  const change = ((lastValue - firstValue) / firstValue) * 100;

  if (change > 2) return "up";
  if (change < -2) return "down";
  return "sideways";
}

